1	import { encrypt, decrypt } from './encryption.util';
2	
3	const isTestEnv = process.env.NODE_ENV === 'test';
4	
5	/**
6	 * TypeORM column transformer for transparent encryption at rest (string columns).
7	 * Write path: encrypts value. Throws on failure unless NODE_ENV=test.
8	 * Read path: decrypts value. Falls back to plaintext only for legacy/migration data.
9	 */
10	export const encryptedTransformer = {
11	  to(value: string | null): string | null {
12	    if (!value) return value;
13	    try {
14	      return encrypt(value);
15	    } catch {
16	      if (isTestEnv) return value;
17	      throw new Error('Encryption failed — FIELD_ENCRYPTION_KEY must be configured');
18	    }
19	  },
20	  from(value: string | null): string | null {
21	    if (!value) return value;
22	    try {
23	      return decrypt(value);
24	    } catch {
25	      // Read-side fallback: tolerate plaintext from pre-encryption data or test writes
26	      return value;
27	    }
28	  },
29	};
30	
31	/**
32	 * TypeORM column transformer for JSONB columns containing sensitive data.
33	 * Write path: serializes to JSON then encrypts. Throws on failure unless NODE_ENV=test.
34	 * Read path: decrypts then parses JSON. Falls back for legacy plaintext JSONB.
35	 */
36	export const encryptedJsonTransformer = {
37	  to(value: Record<string, unknown> | null): string | Record<string, unknown> | null {
38	    if (!value) return value;
39	    try {
40	      return encrypt(JSON.stringify(value));
41	    } catch {
42	      if (isTestEnv) return value;
43	      throw new Error('Encryption failed — FIELD_ENCRYPTION_KEY must be configured');
44	    }
45	  },
46	  from(value: string | Record<string, unknown> | null): Record<string, unknown> | null {
47	    if (!value) return null;
48	    if (typeof value === 'object') return value;
49	    try {
50	      return JSON.parse(decrypt(value));
51	    } catch {
52	      try { return JSON.parse(value); } catch { return null; }
53	    }
54	  },
55	};
