13	@Entity('users')
14	export class UserEntity {
15	  @PrimaryGeneratedColumn('uuid')
16	  id!: string;
17	
18	  @Column({ type: 'varchar', length: 100, unique: true })
19	  username!: string;
20	
21	  /**
22	   * Encrypted email for confidentiality (non-deterministic, random IV).
23	   * NOT used for lookups — use emailHash instead.
24	   */
25	  @Column({ type: 'varchar', length: 500, transformer: encryptedTransformer })
26	  email!: string;
27	
28	  /**
29	   * Deterministic SHA-256 hash of normalized (lowercased, trimmed) email.
30	   * Used for unique constraint enforcement and email-based lookups.
31	   */
32	  @Column({ name: 'email_hash', type: 'varchar', length: 64, unique: true })
33	  emailHash!: string;
34	
35	  @Column({ name: 'password_hash', type: 'varchar', length: 255 })
36	  passwordHash!: string;
37	
38	  @Column({ type: 'varchar', length: 20 })
39	  role!: string;
40	
41	  @Column({ name: 'can_approve_refunds', type: 'boolean', default: false })
42	  canApproveRefunds!: boolean;
43	
44	  @Column({ name: 'full_name', type: 'varchar', length: 200 })
45	  fullName!: string;
46	
47	  @Column({ name: 'phone_encrypted', type: 'bytea', nullable: true })
48	  phoneEncrypted!: Buffer | null;
49	
50	  @Column({ name: 'is_active', type: 'boolean', default: true })
51	  isActive!: boolean;
52	
53	  @Column({ name: 'locked_until', type: 'timestamptz', nullable: true })
54	  lockedUntil!: Date | null;
55	
56	  @CreateDateColumn({ name: 'created_at', type: 'timestamptz' })
57	  createdAt!: Date;
58	
59	  @UpdateDateColumn({ name: 'updated_at', type: 'timestamptz' })
60	  updatedAt!: Date;
61	
62	  @BeforeInsert()
63	  @BeforeUpdate()
64	  computeEmailHash() {
65	    if (this.email) {
66	      this.emailHash = UserEntity.hashEmail(this.email);
67	    }
68	  }
69	
70	  static hashEmail(email: string): string {
71	    return crypto.createHash('sha256').update(email.toLowerCase().trim()).digest('hex');
72	  }
