1	import { z } from 'zod';
2	import { AUTH_LIMITS } from '../constants/limits';
3	import { UserRole } from '../constants/roles';
4	
5	export const loginSchema = z.object({
6	  username: z.string().min(1, 'Username is required'),
7	  password: z.string().min(1, 'Password is required'),
8	  deviceFingerprint: z.string().optional(),
9	  captchaId: z.string().uuid().optional(),
10	  captchaAnswer: z.string().optional(),
11	});
12	
13	export const registerSchema = z.object({
14	  username: z
15	    .string()
16	    .min(3, 'Username must be at least 3 characters')
17	    .max(100)
18	    .regex(/^[a-zA-Z0-9_.-]+$/, 'Username can only contain letters, numbers, dots, dashes, and underscores'),
19	  email: z.string().email('Invalid email address'),
20	  password: z
21	    .string()
22	    .min(AUTH_LIMITS.MIN_PASSWORD_LENGTH, `Password must be at least ${AUTH_LIMITS.MIN_PASSWORD_LENGTH} characters`)
23	    .regex(/[A-Z]/, 'Password must contain at least one uppercase letter')
24	    .regex(/[a-z]/, 'Password must contain at least one lowercase letter')
25	    .regex(/[0-9]/, 'Password must contain at least one number')
26	    .regex(/[^a-zA-Z0-9]/, 'Password must contain at least one special character'),
27	  fullName: z.string().min(1, 'Full name is required').max(200),
28	});
29	
30	export const refreshTokenSchema = z.object({
31	  refreshToken: z.string().min(1, 'Refresh token is required'),
32	});
33	
34	export type LoginInput = z.infer<typeof loginSchema>;
35	export type RegisterInput = z.infer<typeof registerSchema>;
36	export type RefreshTokenInput = z.infer<typeof refreshTokenSchema>;
