12	import * as bcrypt from 'bcrypt';
13	import { UserEntity } from '../../../infrastructure/persistence/entities/user.entity';
14	import { LoginAttemptEntity } from '../../../infrastructure/persistence/entities/login-attempt.entity';
15	import { DeviceFingerprintEntity } from '../../../infrastructure/persistence/entities/device-fingerprint.entity';
16	import { IUserRepository, USER_REPOSITORY } from '../ports/user.repository.port';
17	import { CaptchaService } from '../../../infrastructure/security/captcha.service';
18	import { AnomalyDetectorService } from './anomaly-detector.service';
19	import { AUTH_LIMITS, CAPTCHA_LIMITS } from '@checc/shared/constants/limits';
20	import { ErrorCodes } from '@checc/shared/constants/error-codes';
21	import { WinstonLogger } from '../../../infrastructure/logging/winston.logger';
22	import type { TokenPayload } from '@checc/shared/types/auth.types';
23	import type { RegisterInput, LoginInput } from '@checc/shared/schemas/auth.schema';
24	import { UserRole } from '@checc/shared/constants/roles';
