26	@Injectable()
27	export class AuthService {
28	  private readonly logger = new WinstonLogger();
29	
30	  constructor(
31	    @Inject(USER_REPOSITORY)
32	    private readonly userRepo: IUserRepository,
33	    @InjectRepository(LoginAttemptEntity)
34	    private readonly loginAttemptRepo: Repository<LoginAttemptEntity>,
35	    @InjectRepository(DeviceFingerprintEntity)
36	    private readonly deviceFingerprintRepo: Repository<DeviceFingerprintEntity>,
37	    private readonly jwtService: JwtService,
38	    private readonly captchaService: CaptchaService,
39	    private readonly anomalyDetector: AnomalyDetectorService,
40	  ) {}
41	
42	  async register(input: RegisterInput, ipAddress?: string) {
43	    const existingUsername = await this.userRepo.findByUsername(input.username);
44	    if (existingUsername) {
45	      throw new ConflictException({
46	        message: 'Username already taken',
47	        errorCode: ErrorCodes.USERNAME_TAKEN,
48	      });
49	    }
50	
51	    const existingEmail = await this.userRepo.findByEmail(input.email);
52	    if (existingEmail) {
53	      throw new ConflictException({
54	        message: 'Email already taken',
55	        errorCode: ErrorCodes.EMAIL_TAKEN,
56	      });
57	    }
58	
59	    const passwordHash = await bcrypt.hash(input.password, 12);
60	    const user = await this.userRepo.create({
61	      username: input.username,
62	      email: input.email,
63	      passwordHash,
64	      fullName: input.fullName,
65	      role: UserRole.PATIENT,
66	      canApproveRefunds: false,
67	      isActive: true,
68	    });
69	
70	    this.logger.log(`User registered: ${user.username} (${user.role})`, 'AuthService');
71	
72	    // Record registration event for IP-based anomaly tracking
73	    // Uses '__registration__' fingerprint to distinguish from login events
74	    if (ipAddress) {
75	      await this.recordLoginAttempt(user.id, ipAddress, '__registration__', true);
76	      this.anomalyDetector.checkBulkRegistration(ipAddress).catch(() => {});
77	    }
78	
79	    return this.buildUserDto(user);
80	  }
81	
82	  async login(input: LoginInput, ipAddress: string) {
83	    // Server-driven CAPTCHA escalation: require CAPTCHA after suspicious activity threshold
84	    const recentFailedWindow = new Date(Date.now() - AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
85	    const recentFailedFromIp = await this.loginAttemptRepo.count({
86	      where: {
87	        ipAddress,
88	        success: false,
89	        attemptedAt: MoreThan(recentFailedWindow),
90	      },
91	    });
92	
93	    const captchaRequired = recentFailedFromIp >= CAPTCHA_LIMITS.MAX_CONSECUTIVE_FAILURES;
94	
95	    if (captchaRequired && (!input.captchaId || !input.captchaAnswer)) {
96	      throw new ForbiddenException({
97	        message: 'CAPTCHA is required due to suspicious login activity',
98	        errorCode: ErrorCodes.CAPTCHA_REQUIRED,
99	      });
100	    }
101	
102	    // Validate CAPTCHA if provided (always validate when present, even if not required)
103	    if (input.captchaId && input.captchaAnswer) {
104	      const captchaValid = await this.captchaService.verify(input.captchaId, input.captchaAnswer);
105	      if (!captchaValid) {
106	        throw new UnauthorizedException({
107	          message: 'Invalid or expired CAPTCHA',
108	          errorCode: ErrorCodes.CAPTCHA_INVALID,
109	        });
110	      }
111	    }
112	
113	    const user = await this.userRepo.findByUsername(input.username);
114	
115	    if (!user) {
116	      await this.recordLoginAttempt(null, ipAddress, input.deviceFingerprint, false);
117	      throw new UnauthorizedException({
118	        message: 'Invalid username or password',
119	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
120	      });
121	    }
122	
123	    // Check lockout
124	    if (user.lockedUntil && user.lockedUntil > new Date()) {
125	      throw new ForbiddenException({
126	        message: `Account locked until ${user.lockedUntil.toISOString()}`,
127	        errorCode: ErrorCodes.ACCOUNT_LOCKED,
128	      });
129	    }
130	
131	    // Verify password
132	    const valid = await bcrypt.compare(input.password, user.passwordHash);
133	    await this.recordLoginAttempt(user.id, ipAddress, input.deviceFingerprint, valid);
134	
135	    if (!valid) {
136	      await this.checkAndLockAccount(user);
137	      throw new UnauthorizedException({
138	        message: 'Invalid username or password',
139	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
140	      });
141	    }
142	
143	    if (!user.isActive) {
144	      throw new ForbiddenException({
145	        message: 'Account is deactivated',
146	        errorCode: ErrorCodes.FORBIDDEN,
147	      });
148	    }
149	
150	    // Step-up: require CAPTCHA when logging in from an untrusted device
151	    if (input.deviceFingerprint) {
152	      const deviceRecord = await this.deviceFingerprintRepo.findOne({
153	        where: { userId: user.id, fingerprint: input.deviceFingerprint },
154	      });
155	
156	      const isUntrustedDevice = !deviceRecord || !deviceRecord.isTrusted;
157	      if (isUntrustedDevice && (!input.captchaId || !input.captchaAnswer)) {
158	        // Only enforce step-up if the user has logged in from a trusted device before
159	        const hasTrustedDevices = await this.deviceFingerprintRepo.count({
160	          where: { userId: user.id, isTrusted: true },
161	        });
162	        if (hasTrustedDevices > 0) {
163	          throw new ForbiddenException({
164	            message: 'CAPTCHA is required when logging in from an unrecognized device',
165	            errorCode: ErrorCodes.CAPTCHA_REQUIRED,
166	          });
167	        }
168	      }
169	    }
170	
171	    // Clear any lock on successful login
172	    if (user.lockedUntil) {
173	      await this.userRepo.update(user.id, { lockedUntil: null });
174	    }
175	
176	    // Track device fingerprint for known-device detection
177	    if (input.deviceFingerprint) {
178	      await this.recordDeviceFingerprint(user.id, input.deviceFingerprint);
179	    }
180	
181	    const tokens = this.generateTokens(user);
182	    this.logger.log(`Login successful: ${user.username}`, 'AuthService');
183	
184	    return {
185	      ...tokens,
186	      user: this.buildUserDto(user),
187	    };
188	  }
189	
190	  async validateToken(payload: TokenPayload) {
191	    const user = await this.userRepo.findById(payload.sub);
192	    if (!user || !user.isActive) return null;
193	    return this.buildUserDto(user);
194	  }
195	
196	  async getMe(userId: string) {
197	    const user = await this.userRepo.findById(userId);
198	    if (!user) {
199	      throw new UnauthorizedException({
200	        message: 'User not found',
201	        errorCode: ErrorCodes.INVALID_CREDENTIALS,
202	      });
203	    }
204	    return { user: this.buildUserDto(user) };
205	  }
206	
207	  async verifyCredentials(username: string, password: string): Promise<UserEntity | null> {
208	    const user = await this.userRepo.findByUsername(username);
209	    if (!user) return null;
210	    if (!user.isActive) return null;
211	    if (user.lockedUntil && user.lockedUntil > new Date()) return null;
212	    const valid = await bcrypt.compare(password, user.passwordHash);
213	    return valid ? user : null;
214	  }
215	
216	  async trustDevice(userId: string, fingerprint: string) {
217	    const record = await this.deviceFingerprintRepo.findOne({
218	      where: { userId, fingerprint },
219	    });
220	    if (!record) {
221	      throw new NotFoundException({
222	        message: 'Device not found',
223	        errorCode: ErrorCodes.DEVICE_UNTRUSTED,
224	      });
225	    }
226	    record.isTrusted = true;
227	    await this.deviceFingerprintRepo.save(record);
228	    this.logger.log(`Device trusted for user ${userId}`, 'AuthService');
229	  }
230	
231	  async revokeDevice(userId: string, fingerprint: string) {
232	    const record = await this.deviceFingerprintRepo.findOne({
233	      where: { userId, fingerprint },
234	    });
235	    if (!record) {
236	      throw new NotFoundException({
237	        message: 'Device not found',
238	        errorCode: ErrorCodes.DEVICE_UNTRUSTED,
239	      });
240	    }
241	    record.isTrusted = false;
242	    await this.deviceFingerprintRepo.save(record);
243	    this.logger.log(`Device trust revoked for user ${userId}`, 'AuthService');
244	  }
245	
246	  async getUserDevices(userId: string) {
247	    return this.deviceFingerprintRepo.find({
248	      where: { userId },
249	      order: { lastSeenAt: 'DESC' },
250	    });
251	  }
252	
253	  private async recordLoginAttempt(
254	    userId: string | null,
255	    ipAddress: string,
256	    deviceFingerprint: string | undefined,
257	    success: boolean,
258	  ) {
259	    const attempt = this.loginAttemptRepo.create({
260	      userId,
261	      ipAddress,
262	      deviceFingerprint: deviceFingerprint || null,
263	      success,
264	    });
265	    await this.loginAttemptRepo.save(attempt);
266	  }
267	
268	  private async recordDeviceFingerprint(userId: string, fingerprint: string) {
269	    const existing = await this.deviceFingerprintRepo.findOne({
270	      where: { userId, fingerprint },
271	    });
272	
273	    if (existing) {
274	      existing.lastSeenAt = new Date();
275	      await this.deviceFingerprintRepo.save(existing);
276	    } else {
277	      const record = this.deviceFingerprintRepo.create({
278	        userId,
279	        fingerprint,
280	        firstSeenAt: new Date(),
281	        lastSeenAt: new Date(),
282	        isTrusted: false,
283	      });
284	      await this.deviceFingerprintRepo.save(record);
285	    }
286	  }
287	
288	  private async checkAndLockAccount(user: UserEntity) {
289	    const windowStart = new Date(Date.now() - AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
290	    const recentFailed = await this.loginAttemptRepo.count({
291	      where: {
292	        userId: user.id,
293	        success: false,
294	        attemptedAt: MoreThan(windowStart),
295	      },
296	    });
297	
298	    if (recentFailed >= AUTH_LIMITS.MAX_LOGIN_ATTEMPTS) {
299	      const lockUntil = new Date(Date.now() + AUTH_LIMITS.LOCKOUT_DURATION_MINUTES * 60 * 1000);
300	      await this.userRepo.update(user.id, { lockedUntil: lockUntil });
301	      this.logger.warn(
302	        `Account locked: ${user.username} (${recentFailed} failed attempts)`,
303	        'AuthService',
304	      );
305	    }
306	  }
307	
308	  private generateTokens(user: UserEntity) {
309	    const payload: TokenPayload = {
310	      sub: user.id,
311	      username: user.username,
312	      role: user.role as UserRole,
313	      canApproveRefunds: user.canApproveRefunds,
314	    };
315	
316	    return {
317	      accessToken: this.jwtService.sign(payload),
318	      refreshToken: this.jwtService.sign(payload, {
319	        expiresIn: process.env.JWT_REFRESH_EXPIRES_IN || '7d',
320	      }),
321	    };
322	  }
323	
324	  private buildUserDto(user: UserEntity) {
325	    return {
326	      id: user.id,
327	      username: user.username,
328	      email: user.email,
329	      role: user.role as UserRole,
330	      fullName: user.fullName,
331	      canApproveRefunds: user.canApproveRefunds,
332	      isActive: user.isActive,
333	      createdAt: user.createdAt.toISOString(),
334	    };
335	  }
336	}
