1	async function getCanvasFingerprint(): Promise<string> {
2	  const canvas = document.createElement('canvas');
3	  const ctx = canvas.getContext('2d');
4	  if (!ctx) return '';
5	
6	  canvas.width = 200;
7	  canvas.height = 50;
8	  ctx.textBaseline = 'top';
9	  ctx.font = '14px Arial';
10	  ctx.fillStyle = '#f60';
11	  ctx.fillRect(125, 1, 62, 20);
12	  ctx.fillStyle = '#069';
13	  ctx.fillText('CHECC fingerprint', 2, 15);
14	  ctx.fillStyle = 'rgba(102, 204, 0, 0.7)';
15	  ctx.fillText('CHECC fingerprint', 4, 17);
16	
17	  return canvas.toDataURL();
18	}
19	
20	async function getAudioFingerprint(): Promise<string> {
21	  try {
22	    const audioCtx = new (window.AudioContext || (window as unknown as Record<string, unknown>).webkitAudioContext)();
23	    const oscillator = audioCtx.createOscillator();
24	    const analyser = audioCtx.createAnalyser();
25	    const gain = audioCtx.createGain();
26	
27	    oscillator.type = 'triangle';
28	    oscillator.frequency.setValueAtTime(10000, audioCtx.currentTime);
29	    gain.gain.setValueAtTime(0, audioCtx.currentTime);
30	
31	    oscillator.connect(analyser);
32	    analyser.connect(gain);
33	    gain.connect(audioCtx.destination);
34	
35	    oscillator.start(0);
36	
37	    const buffer = new Float32Array(analyser.frequencyBinCount);
38	    analyser.getFloatFrequencyData(buffer);
39	
40	    oscillator.stop();
41	    await audioCtx.close();
42	
43	    return buffer.slice(0, 10).join(',');
44	  } catch {
45	    return '';
46	  }
47	}
48	
49	function getHardwareAttributes(): string {
50	  const attrs = [
51	    screen.width,
52	    screen.height,
53	    screen.colorDepth,
54	    navigator.language,
55	    navigator.platform,
56	    Intl.DateTimeFormat().resolvedOptions().timeZone,
57	    navigator.hardwareConcurrency || 0,
58	  ];
59	  return attrs.join('|');
60	}
61	
62	async function sha256(input: string): Promise<string> {
63	  // crypto.subtle requires secure context (HTTPS/localhost)
64	  // Fall back to simple hash for insecure contexts (Docker HTTP, LAN)
65	  if (typeof crypto !== 'undefined' && crypto.subtle) {
66	    const encoder = new TextEncoder();
67	    const data = encoder.encode(input);
68	    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
69	    const hashArray = Array.from(new Uint8Array(hashBuffer));
70	    return hashArray.map((b) => b.toString(16).padStart(2, '0')).join('');
71	  }
72	  // Simple fallback hash for non-secure contexts
73	  let hash = 0;
74	  for (let i = 0; i < input.length; i++) {
75	    const char = input.charCodeAt(i);
76	    hash = ((hash << 5) - hash) + char;
77	    hash = hash & hash;
78	  }
79	  return Math.abs(hash).toString(16).padStart(16, '0');
80	}
81	
82	export async function generateFingerprint(): Promise<string> {
83	  try {
84	    const [canvas, audio, hardware] = await Promise.all([
85	      getCanvasFingerprint().catch(() => ''),
86	      getAudioFingerprint().catch(() => ''),
87	      Promise.resolve(getHardwareAttributes()),
88	    ]);
89	
90	    const combined = `${canvas}|${audio}|${hardware}`;
91	    return await sha256(combined);
92	  } catch {
93	    // Fingerprinting failed (e.g., insecure context) — return a basic fallback
94	    return Date.now().toString(16);
95	  }
96	}
