1	import * as crypto from 'crypto';
2	
3	const ALGORITHM = 'aes-256-gcm';
4	const IV_LENGTH = 12;
5	const AUTH_TAG_LENGTH = 16; // eslint-disable-line @typescript-eslint/no-unused-vars
6	
7	function getKey(): Buffer {
8	  const key = process.env.FIELD_ENCRYPTION_KEY;
9	  if (!key) {
10	    if (process.env.NODE_ENV === 'production') {
11	      throw new Error('FIELD_ENCRYPTION_KEY environment variable must be set in production');
12	    }
13	    throw new Error('FIELD_ENCRYPTION_KEY environment variable is not set');
14	  }
15	  // Ensure key is 32 bytes for AES-256
16	  return crypto.createHash('sha256').update(key).digest();
17	}
18	
19	export function encrypt(plaintext: string, key?: string): string {
20	  const derivedKey = key
21	    ? crypto.createHash('sha256').update(key).digest()
22	    : getKey();
23	
24	  const iv = crypto.randomBytes(IV_LENGTH);
25	  const cipher = crypto.createCipheriv(ALGORITHM, derivedKey, iv);
26	
27	  let encrypted = cipher.update(plaintext, 'utf8', 'hex');
28	  encrypted += cipher.final('hex');
29	
30	  const authTag = cipher.getAuthTag();
31	
32	  // Format: iv:authTag:ciphertext (all hex)
33	  return `${iv.toString('hex')}:${authTag.toString('hex')}:${encrypted}`;
34	}
35	
36	export function decrypt(ciphertext: string, key?: string): string {
37	  const derivedKey = key
38	    ? crypto.createHash('sha256').update(key).digest()
39	    : getKey();
40	
41	  const parts = ciphertext.split(':');
42	  if (parts.length !== 3) {
43	    throw new Error('Invalid ciphertext format');
44	  }
45	
46	  const iv = Buffer.from(parts[0], 'hex');
47	  const authTag = Buffer.from(parts[1], 'hex');
48	  const encryptedData = parts[2];
49	
50	  const decipher = crypto.createDecipheriv(ALGORITHM, derivedKey, iv);
51	  decipher.setAuthTag(authTag);
52	
53	  let decrypted = decipher.update(encryptedData, 'hex', 'utf8');
54	  decrypted += decipher.final('utf8');
55	
56	  return decrypted;
57	}
