24	        errorCode: ErrorCodes.FORBIDDEN,
25	      });
26	    }
27	
28	    const hasRole = requiredRoles.some((role) => user.role === role);
29	    if (!hasRole) {
30	      throw new ForbiddenException({
31	        message: 'Insufficient permissions',
32	        errorCode: ErrorCodes.INSUFFICIENT_ROLE,
33	      });
