7	} from '@nestjs/common';
8	import { Response } from 'express';
9	import { Public } from '../decorators/public.decorator';
10	import * as fs from 'fs';
11	import * as path from 'path';
12	
13	@Controller('media')
14	export class MediaController {
15	  private readonly storagePath: string;
16	
17	  constructor() {
18	    this.storagePath = process.env.MEDIA_STORAGE_PATH || 'data/media';
19	  }
20	
21	  @Public()
22	  @Get(':filename')
23	  async serveMedia(@Param('filename') filename: string, @Res() res: Response) {
24	    // Sanitize filename to prevent directory traversal
25	    const safeName = path.basename(filename);
26	    const filePath = path.join(this.storagePath, safeName);
27	    const resolvedPath = path.resolve(filePath);
28	    const resolvedStorage = path.resolve(this.storagePath);
29	
30	    if (!resolvedPath.startsWith(resolvedStorage)) {
31	      throw new NotFoundException('File not found');
32	    }
33	
34	    if (!fs.existsSync(resolvedPath)) {
35	      throw new NotFoundException('File not found');
36	    }
37	
38	    // Determine content type from extension
39	    const ext = path.extname(safeName).toLowerCase();
40	    const mimeTypes: Record<string, string> = {
41	      '.jpg': 'image/jpeg',
42	      '.jpeg': 'image/jpeg',
43	      '.png': 'image/png',
44	      '.gif': 'image/gif',
45	      '.webp': 'image/webp',
46	      '.svg': 'image/svg+xml',
47	      '.mp3': 'audio/mpeg',
48	      '.wav': 'audio/wav',
49	      '.ogg': 'audio/ogg',
50	      '.mp4': 'video/mp4',
51	      '.webm': 'video/webm',
52	    };
53	
54	    const contentType = mimeTypes[ext] || 'application/octet-stream';
55	    res.setHeader('Content-Type', contentType);
56	    res.setHeader('Cache-Control', 'public, max-age=86400');
57	
58	    const stream = fs.createReadStream(resolvedPath);
59	    stream.pipe(res);
60	  }
61	}
