20	@Injectable()
21	export class ContentService {
22	  private readonly logger = new WinstonLogger();
23	
24	  constructor(
25	    @InjectRepository(ArticleEntity)
26	    private readonly articleRepo: Repository<ArticleEntity>,
27	    @InjectRepository(ArticleVersionEntity)
28	    private readonly versionRepo: Repository<ArticleVersionEntity>,
29	    @InjectRepository(MediaAssetEntity)
30	    private readonly mediaAssetRepo: Repository<MediaAssetEntity>,
31	    private readonly sensitiveWordService: SensitiveWordService,
32	    private readonly dataSource: DataSource,
33	  ) {}
34	
35	  /** Strip dangerous HTML (scripts, event handlers) while preserving safe formatting. */
36	  private sanitizeBody(html: string): string {
37	    return sanitizeHtml(html, {
38	      allowedTags: sanitizeHtml.defaults.allowedTags.concat(['img', 'h1', 'h2', 'h3']),
39	      allowedAttributes: {
40	        ...sanitizeHtml.defaults.allowedAttributes,
41	        img: ['src', 'alt', 'width', 'height'],
42	      },
43	      disallowedTagsMode: 'discard',
44	    });
45	  }
46	
47	  async create(input: CreateArticleInput, authorId: string) {
48	    const slug = this.generateSlug(input.title);
49	
50	    // Check slug uniqueness
51	    const existingSlug = await this.articleRepo.findOne({ where: { slug } });
52	    if (existingSlug) {
53	      throw new BadRequestException({
54	        message: 'An article with a similar title already exists',
55	        errorCode: ErrorCodes.ARTICLE_SLUG_TAKEN,
56	      });
57	    }
58	
59	    // Scan for sensitive words
60	    const hits = await this.sensitiveWordService.scan(input.body);
61	
62	    const sanitizedBody = this.sanitizeBody(input.body);
63	
64	    const article = this.articleRepo.create({
65	      title: input.title,
66	      slug,
67	      body: sanitizedBody,
68	      contentType: input.contentType,
69	      status: ContentStatus.DRAFT,
70	      authorId,
71	      currentVersion: 1,
72	      sensitiveWordHits: hits.length > 0 ? (hits as unknown as Record<string, unknown>[]) : null,
73	    });
74	
75	    const saved = await this.articleRepo.save(article);
76	
77	    // Create initial version snapshot
78	    const version = this.versionRepo.create({
79	      articleId: saved.id,
80	      versionNumber: 1,
81	      title: saved.title,
82	      body: sanitizedBody,
83	      contentType: saved.contentType,
84	      createdBy: authorId,
85	    });
86	    await this.versionRepo.save(version);
87	
88	    this.logger.log(`Article created: ${saved.id} by ${authorId}`, 'ContentService');
89	    return saved;
90	  }
91	
92	  async update(id: string, input: UpdateArticleInput, userId: string) {
93	    const article = await this.articleRepo.findOne({ where: { id } });
94	
95	    if (!article) {
96	      throw new NotFoundException({
97	        message: 'Article not found',
98	        errorCode: ErrorCodes.ARTICLE_NOT_FOUND,
99	      });
100	    }
101	
102	    if (article.authorId !== userId) {
103	      throw new ForbiddenException({
104	        message: 'Only the author can update this article',
105	        errorCode: ErrorCodes.RESOURCE_NOT_OWNED,
106	      });
107	    }
108	
109	    if (article.status !== ContentStatus.DRAFT) {
110	      throw new BadRequestException({
111	        message: 'Only DRAFT articles can be updated',
112	        errorCode: ErrorCodes.ARTICLE_NOT_IN_REVIEW,
113	      });
114	    }
115	
116	    if (input.title) {
117	      article.title = input.title;
118	      const newSlug = this.generateSlug(input.title);
119	      const existingSlug = await this.articleRepo.findOne({ where: { slug: newSlug } });
120	      if (existingSlug && existingSlug.id !== id) {
121	        throw new BadRequestException({
122	          message: 'An article with a similar title already exists',
123	          errorCode: ErrorCodes.ARTICLE_SLUG_TAKEN,
124	        });
125	      }
126	      article.slug = newSlug;
127	    }
128	
129	    if (input.body) {
130	      article.body = this.sanitizeBody(input.body);
131	      const hits = await this.sensitiveWordService.scan(input.body);
132	      article.sensitiveWordHits = hits.length > 0 ? (hits as unknown as Record<string, unknown>[]) : null;
133	    }
134	
135	    // Bump version
136	    article.currentVersion = (article.currentVersion || 0) + 1;
137	    const saved = await this.articleRepo.save(article);
138	
139	    // Create version snapshot
140	    const version = this.versionRepo.create({
141	      articleId: saved.id,
142	      versionNumber: saved.currentVersion,
143	      title: saved.title,
144	      body: saved.body,
145	      contentType: saved.contentType,
146	      createdBy: userId,
147	    });
148	    await this.versionRepo.save(version);
149	
150	    this.logger.log(`Article updated: ${saved.id} v${saved.currentVersion}`, 'ContentService');
151	    return saved;
152	  }
153	
154	  async submitForReview(id: string, userId: string) {
155	    const article = await this.articleRepo.findOne({ where: { id } });
156	
157	    if (!article) {
158	      throw new NotFoundException({
159	        message: 'Article not found',
160	        errorCode: ErrorCodes.ARTICLE_NOT_FOUND,
161	      });
162	    }
163	
164	    if (article.authorId !== userId) {
165	      throw new ForbiddenException({
166	        message: 'Only the author can submit for review',
167	        errorCode: ErrorCodes.RESOURCE_NOT_OWNED,
168	      });
169	    }
170	
171	    if (article.status !== ContentStatus.DRAFT) {
172	      throw new BadRequestException({
173	        message: 'Only DRAFT articles can be submitted for review',
174	        errorCode: ErrorCodes.ARTICLE_NOT_IN_REVIEW,
175	      });
176	    }
177	
178	    article.status = ContentStatus.IN_REVIEW;
179	    const saved = await this.articleRepo.save(article);
180	    this.logger.log(`Article submitted for review: ${saved.id}`, 'ContentService');
181	    return saved;
182	  }
183	
184	  async review(id: string, reviewData: ReviewArticleInput, adminId: string) {
185	    return this.dataSource.transaction(async (manager) => {
186	      const article = await manager.findOne(ArticleEntity, {
187	        where: { id },
188	        lock: { mode: 'pessimistic_write' },
189	      });
190	
191	      if (!article) {
192	        throw new NotFoundException({
193	          message: 'Article not found',
194	          errorCode: ErrorCodes.ARTICLE_NOT_FOUND,
195	        });
196	      }
197	
198	      if (article.status !== ContentStatus.IN_REVIEW) {
199	        throw new BadRequestException({
200	          message: 'Article is not in review',
201	          errorCode: ErrorCodes.ARTICLE_NOT_IN_REVIEW,
202	        });
203	      }
204	
205	      article.reviewerId = adminId;
206	
207	      if (reviewData.approved) {
208	        article.status = ContentStatus.PUBLISHED;
