210	      } else {
211	        article.status = ContentStatus.REJECTED;
212	        article.reviewNotes = reviewData.reviewNotes || null;
213	      }
214	
215	      const saved = await manager.save(ArticleEntity, article);
216	      this.logger.log(
217	        `Article reviewed: ${saved.id} - ${reviewData.approved ? 'APPROVED' : 'REJECTED'}`,
218	        'ContentService',
219	      );
220	      return saved;
221	    });
222	  }
223	
224	  async archive(id: string) {
225	    const article = await this.articleRepo.findOne({ where: { id } });
226	
227	    if (!article) {
228	      throw new NotFoundException({
229	        message: 'Article not found',
230	        errorCode: ErrorCodes.ARTICLE_NOT_FOUND,
231	      });
