1	import { Injectable } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository } from 'typeorm';
4	import { CaptchaChallengeEntity } from '../persistence/entities/captcha-challenge.entity';
5	import { CAPTCHA_LIMITS } from '@checc/shared/constants/limits';
6	import { WinstonLogger } from '../logging/winston.logger';
7	
8	@Injectable()
9	export class CaptchaService {
10	  private readonly logger = new WinstonLogger();
11	
12	  constructor(
13	    @InjectRepository(CaptchaChallengeEntity)
14	    private readonly captchaRepo: Repository<CaptchaChallengeEntity>,
15	  ) {}
16	
17	  async generate(): Promise<{ id: string; imageBase64: string; expiresAt: string }> {
18	    const a = Math.floor(Math.random() * 50) + 1;
19	    const b = Math.floor(Math.random() * 50) + 1;
20	    const answer = String(a + b);
21	    const questionText = `${a} + ${b} = ?`;
22	
23	    // Generate a simple text-based image representation as base64
24	    const imageText = this.generateTextImage(questionText);
25	    const imageBase64 = Buffer.from(imageText).toString('base64');
26	
27	    const expiresAt = new Date(Date.now() + CAPTCHA_LIMITS.EXPIRY_MINUTES * 60 * 1000);
28	
29	    const challenge = this.captchaRepo.create({
30	      challengeText: answer,
31	      imageData: Buffer.from(imageBase64),
32	      expiresAt,
33	      isUsed: false,
34	    });
35	
36	    const saved = await this.captchaRepo.save(challenge);
37	
38	    this.logger.log(`Captcha generated: ${saved.id}`, 'CaptchaService');
39	
40	    return {
41	      id: saved.id,
42	      imageBase64,
43	      expiresAt: expiresAt.toISOString(),
44	    };
45	  }
46	
47	  async verify(id: string, answer: string): Promise<boolean> {
48	    const challenge = await this.captchaRepo.findOne({ where: { id } });
49	
50	    if (!challenge) return false;
51	    if (challenge.isUsed) return false;
52	    if (challenge.expiresAt < new Date()) return false;
53	
54	    // Mark as used regardless of answer
55	    challenge.isUsed = true;
56	    await this.captchaRepo.save(challenge);
57	
58	    return challenge.challengeText === answer.trim();
59	  }
60	
61	  private generateTextImage(text: string): string {
62	    // Simple ASCII art style captcha representation
63	    const border = '+' + '-'.repeat(text.length + 4) + '+';
64	    const line = `|  ${text}  |`;
65	    return `${border}\n${line}\n${border}`;
66	  }
67	}
