160	      });
161	    }
162	
163	    // Validate supervisor credentials BEFORE entering the transaction
164	    let approvedById: string;
165	    if (requestingUserCanApprove) {
166	      approvedById = requestingUserId;
167	    } else {
168	      if (!input.supervisorUsername || !input.supervisorPassword) {
169	        throw new ForbiddenException({
170	          message: 'Supervisor credentials are required to approve this refund',
171	          errorCode: ErrorCodes.REFUND_SUPERVISOR_REQUIRED,
172	        });
173	      }
174	      const supervisor = await this.authService.verifyCredentials(
175	        input.supervisorUsername,
176	        input.supervisorPassword,
177	      );
178	      if (!supervisor) {
179	        throw new ForbiddenException({
180	          message: 'Invalid supervisor credentials',
181	          errorCode: ErrorCodes.REFUND_INVALID_SUPERVISOR,
182	        });
183	      }
184	      if (!supervisor.canApproveRefunds) {
185	        throw new ForbiddenException({
186	          message: 'Supervisor does not have refund approval permission',
187	          errorCode: ErrorCodes.REFUND_INVALID_SUPERVISOR,
188	        });
189	      }
190	      approvedById = supervisor.id;
191	    }
