193	    const result = await this.dataSource.transaction(async (manager) => {
194	      // Lock payment row to prevent concurrent double-refund
195	      const payment = await manager.findOne(PaymentEntity, {
196	        where: { id: input.paymentId },
197	        lock: { mode: 'pessimistic_write' },
198	      });
199	
200	      if (!payment) {
201	        throw new NotFoundException({
202	          message: 'Payment not found',
203	          errorCode: ErrorCodes.PAYMENT_NOT_FOUND,
204	        });
205	      }
206	
207	      if (payment.status !== PaymentStatus.PAID) {
208	        throw new BadRequestException({
209	          message: 'Payment is not in PAID status',
210	          errorCode: ErrorCodes.PAYMENT_ALREADY_PROCESSED,
211	        });
212	      }
213	
214	      if (Number(input.amount) > Number(payment.amount)) {
215	        throw new BadRequestException({
216	          message: `Refund amount (${input.amount}) exceeds payment amount (${payment.amount})`,
217	          errorCode: ErrorCodes.PAYMENT_ALREADY_PROCESSED,
218	        });
219	      }
220	
221	      const now = new Date();
222	
