224	        paymentId: payment.id,
225	        amount: input.amount,
226	        reasonCode: input.reasonCode,
227	        reasonDetail: input.reasonDetail || null,
228	        requestedBy: requestingUserId,
229	        approvedBy: approvedById,
230	        approvedAt: now,
231	      });
232	      const savedRefund = await manager.save(RefundEntity, refund);
233	
234	      payment.status = PaymentStatus.REFUNDED;
235	      await manager.save(PaymentEntity, payment);
236	
